class NumArray:
    def __init__(self, nums):
        self.n = len(nums)
        self.a = [0] * self.n
        self.tree = [0] * (self.n + 1)
        for i, v in enumerate(nums):
            self.update(i, v)
    def update(self, index, val):
        delta = val - self.a[index]
        self.a[index] = val
        i = index + 1
        while i <= self.n:
            self.tree[i] += delta
            i += i & (-i)
    def _prefix(self, i):
        s = 0
        while i > 0:
            s += self.tree[i]
            i -= i & (-i)
        return s
    def sumRange(self, left, right):
        return self._prefix(right + 1) - self._prefix(left)

