class NumArray {
    constructor(nums) {
        this.n = nums.length;
        this.a = new Array(this.n).fill(0);
        this.tree = new Array(this.n + 1).fill(0);
        for (let i = 0; i < this.n; i++) this.update(i, nums[i]);
    }
    update(index, val) {
        const delta = val - this.a[index];
        this.a[index] = val;
        let i = index + 1;
        while (i <= this.n) {
            this.tree[i] += delta;
            i += i & (-i);
        }
    }
    _prefix(i) {
        let s = 0;
        while (i > 0) {
            s += this.tree[i];
            i -= i & (-i);
        }
        return s;
    }
    sumRange(left, right) {
        return this._prefix(right + 1) - this._prefix(left);
    }
}
